10â†’/**
11â†’ * Require one or more roles. If user's role is not in the list, return 403.
12â†’ */
13â†’export function requireRole(...roles: UserRole[]) {
14â†’  return (req: Request, res: Response, next: NextFunction): void => {
15â†’    if (!req.user) {
16â†’      forbidden(res, 'Not authenticated');
17â†’      return;
18â†’    }
19â†’    if (!roles.includes(req.user.role)) {
20â†’      forbidden(res, `Access denied. Required role: ${roles.join(' or ')}`);
21â†’      return;
22â†’    }
23â†’    next();
24â†’  };
25â†’}
