41â†’ */
42â†’export function validate(schema: ZodSchema) {
43â†’  return (req: Request, res: Response, next: NextFunction): void => {
44â†’    const result = schema.safeParse(req.body);
45â†’    if (!result.success) {
46â†’      const flattened = result.error.flatten();
47â†’      // Merge formErrors into fieldErrors so they reach the client
48â†’      const errors = {
49â†’        ...flattened.fieldErrors,
50â†’        ...(flattened.formErrors.length > 0 ? { _form: flattened.formErrors } : {}),
51â†’      };
52â†’      validationError(res, errors);
53â†’      return;
54â†’    }
55â†’    req.body = result.data;
56â†’    next();
57â†’  };
58â†’}
